-items:center;gap:6px;padding:8px 10px;justify-content:center}.zact{width:32px;height:32px;border:none;border-radius:8px;background:rgba(99,102,241,.15);color:#a5b4fc;cursor:pointer;display:flex;align-items:center;justify-content:center}.zact svg{width:14px;height:14px}.zact.del{background:rgba(239,68,68,.12);color:#f87171}.add-zone-btn{margin:4px 16px 12px;padding:14px;background:rgba(99,102,241,.08);border:2px dashed rgba(99,102,241,.28);border-radius:14px;color:#a5b4fc;font-size:14px;font-weight:600;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:8px}.prog-bar{height:5px;background:rgba(99,102,241,.15);border-radius:3px;overflow:hidden}.prog-fill{height:100%;background:linear-gradient(90deg,#6366f1,#8b5cf6);border-radius:3px;transition:width .5s}.prog-lbl{font-size:11px;color:#94a3b8;margin-top:5px}.rec-ov{display:none;position:fixed;inset:0;z-index:1000;background:rgba(3,7,18,.72);backdrop-filter:blur(8px);align-items:flex-end;justify-content:center;padding-bottom:100px}.rec-ov.active{display:flex}.rec-box{background:rgba(15,23,42,.97);border:1px solid rgba(99,102,241,.4);border-radius:20px;padding:20px;width:calc(100% - 32px)}.rec-ind{display:flex;align-items:center;gap:10px;margin-bottom:14px}.rec-dot{width:12px;height:12px;border-radius:50%;background:#ef4444;animation:recPulse 1s infinite}.rec-dot.done{background:#22c55e;animation:none}@keyframes recPulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.5;transform:scale(.8)}}.rec-lbl{font-size:13px;font-weight:700}.rec-trans{min-height:46px;font-size:16px;color:#c7d2fe;margin-bottom:14px;line-height:1.4}.rec-send{width:100%;padding:14px;border:none;border-radius:12px;background:linear-gradient(135deg,#6366f1,#8b5cf6);color:#fff;font-size:15px;font-weight:700;cursor:pointer}.rec-cancel{width:100%;margin-top:8px;padding:10px;border:none;border-radius:12px;background:transparent;color:#94a3b8;font-size:13px;cursor:pointer}.modal-ov{display:none;position:fixed;inset:0;z-index:600;background:rgba(0,0,0,.75);backdrop-filter:blur(8px);align-items:flex-end;justify-content:center}.modal-ov.open{display:flex}.modal-box{background:#0c1525;border:1px solid rgba(99,102,241,.3);border-radius:20px 20px 0 0;padding:20px;width:100%;max-height:88dvh;overflow-y:auto}.mhandle{width:36px;height:4px;background:rgba(99,102,241,.3);border-radius:2px;margin:0 auto 16px}.zt-tabs{display:flex;gap:6px;flex-wrap:wrap}.zt-tab{padding:7px 13px;border-radius:20px;font-size:12px;font-weight:600;border:1.5px solid rgba(99,102,241,.2);background:transparent;color:#94a3b8;cursor:pointer}.zt-tab.active{background:rgba(99,102,241,.22);border-color:#6366f1;color:#a5b4fc}.photo-preview{width:100%;height:140px;background:rgba(99,102,241,.07);border:2px dashed rgba(99,102,241,.3);border-radius:12px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:8px;position:relative;overflow:hidden}.photo-preview img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;border-radius:10px}.name-input{flex:1;min-height:44px;padding:10px 14px;background:rgba(99,102,241,.07);border:1.5px solid rgba(99,102,241,.2);border-radius:10px;font-size:15px;color:#e2e8f0;font-family:inherit;outline:none}.name-input:focus{border-color:#6366f1}.voice-mini-btn{padding:10px 14px;border:1.5px solid rgba(239,68,68,.3);border-radius:10px;background:rgba(239,68,68,.1);color:#fca5a5;cursor:pointer;display:flex;align-items:center;gap:6px;font-size:13px;font-weight:700;flex-shrink:0}.voice-mini-btn svg{width:16px;height:16px}.czc{background:rgba(15,23,42,.7);border:1px solid rgba(99,102,241,.2);border-radius:16px;overflow:hidden;margin:0 16px 10px;cursor:pointer;display:flex;align-items:stretch}.czc:active{opacity:.75}.czc-photo{width:78px;flex-shrink:0;background:rgba(99,102,241,.08);display:flex;align-items:center;justify-content:center;min-height:78px;position:relative;overflow:hidden}.czc-photo img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover}.czc-body{flex:1;padding:13px}.czc-name{font-size:15px;font-weight:700;margin-bottom:4px}.czc-arr{display:flex;align-items:center;padding:0 12px;color:#6366f1}.czc-arr svg{width:18px;height:18px}.sess-banner{margin:12px 16px;background:rgba(99,102,241,.14);border:1px solid rgba(99,102,241,.28);border-radius:14px;padding:14px}.camera-ov{position:fixed;inset:0;z-index:700;background:#000;display:none;flex-direction:column}.camera-ov.open{display:flex}.camera-video{flex:1;object-fit:cover}.cam-controls{position:absolute;bottom:40px;left:0;right:0;display:flex;justify-content:center;gap:20px}.cam-btn{width:56px;height:56px;border-radius:50%;border:2px solid rgba(255,255,255,.3);background:rgba(255,255,255,.1);color:#fff;font-size:22px;cursor:pointer;display:flex;align-items:center;justify-content:center}.cam-btn.capture{background:#fff;color:#000}.cam-btn.close-cam{background:rgba(239,68,68,.3);border-color:rgba(239,68,68,.5)}.inv-toast{position:fixed;bottom:calc(var(--nav)+36px);left:50%;transform:translateX(-50%);background:rgba(12,21,37,.97);border:1px solid rgba(99,102,241,.3);border-radius:12px;padding:10px 18px;font-size:13px;color:#e2e8f0;z-index:2000;white-space:nowrap;pointer-events:none;opacity:0;transition:opacity .3s}.inv-toast.show{opacity:1}.inv-toast.err{border-color:rgba(239,68,68,.4)}.inv-toast.ok{border-color:rgba(34,197,94,.4)}.inv-toast.warn{border-color:rgba(245,158,11,.4)}.bottom-nav{position:fixed;bottom:0;left:0;right:0;height:var(--nav);background:rgba(3,7,18,.97);border-top:1px solid rgba(255,255,255,.04);display:flex;z-index:100}.bottom-nav-tab{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:2px;font-size:8px;font-weight:600;text-decoration:none}.bottom-nav-tab svg{width:18px;height:18px;stroke-width:1.5;fill:none}.bottom-nav-tab.active{color:#a5b4fc}.bottom-nav-tab.active svg{stroke:#a5b4fc}.bottom-nav-tab.inactive{color:rgba(165,180,252,.45)}.bottom-nav-tab.inactive svg{stroke:rgba(165,180,252,.45)}
